import { PrismaClient } from '@prisma/client';
import * as bcrypt from 'bcryptjs';

const prisma = new PrismaClient();

const HOUR = 3_600_000;
const DAY = 24 * HOUR;

// ─── Quest blueprint ────────────────────────────────────────────────────────
interface QuestSeed {
    title: string;
    description: string;
    sponsor: string;
    type: 'FCFS' | 'LEADERBOARD' | 'LUCKY_DRAW';
    status: 'draft' | 'live' | 'scheduled' | 'completed';
    rewardAmount: number;
    rewardType: string;
    totalSlots: number;
    tags: string[];
    expiresAt: Date | null;

